SourceCode.Declaration:
/// <summary>
/// </summary>
///<remarks>
///</remarks>
public class DBMUpdateTableStatisticsService extends SysOperationServiceBase
{
    private str sampleDef;
}

Method.Source:
/// <summary>
/// An entry point of the service operation.
/// </summary>
/// <param name = "_contract">
/// Contract instance for service operation.
/// </param>
public void process(DBMUpdateTableStatisticsContract _contract)
{
    sampleDef = this.getSampleDef(_contract);
    SetEnumerator se = _contract.parmTables().getEnumerator();
    while (se.moveNext())
    {
        this.updateStats(se.current());
    }
}

/// <summary>
/// updates database statistics for a single table
/// </summary>
/// <param name = "_contract">
/// Contract instance for service operation.
/// </param>
protected void updateStats(TableName _tableName)
{
    utcdatetime startTime = DateTimeUtil::getSystemDateTime();
    Connection connection = new Connection();
    str statementText = strFmt('UPDATE STATISTICS dbo.%1 WITH %2',_tableName, sampleDef);
    Statement statement = connection.createStatement();
    SqlStatementExecutePermission perm;
    perm = new SqlStatementExecutePermission(statementText);
    perm.assert();
    statement.executeUpdateWithParameters(statementText,SqlParams::create());
    CodeAccessPermission::revertAssert();
    Info(strFmt("@DBMUpdateTableStats:StatisticsWereUpdated",
                _tableName,
        time2Str(DateTimeUtil::getDifference(DateTimeUtil::getSystemDateTime(),startTime),TimeSeparator::Colon,TimeFormat::Hour24)));
}

private str getSampleDef(DBMUpdateTableStatisticsContract _contract)
{
    str ret;
    switch (_contract.parmSamplingMode())
    {
        case DBMStatSamplingMode::FullScan:
            ret = 'FULLSCAN';
            break;
        case DBMStatSamplingMode::Resample:
            ret = 'RESAMPLE';
            break;
        case DBMStatSamplingMode::Sample:
            ret = strFmt('SAMPLE %1 %2',
                _contract.parmSampleSize(),
                _contract.parmSamplingScope() == DBMStatSamplingScope::Rows ? 'ROWS' : 'PERCENT');
            break;
    }
    return ret;
}
